*******************************************************************************;
* Program: relrec.sas
* Purpose: Create SDTM RELREC (Related Records) domain
* Study: CDISCPILOT01
* Standard: SDTM IG v3.1.2
* Author: Clinical Statistical Programmer
* Date: [Date]
*******************************************************************************;

%let studyid = CDISCPILOT01;

*******************************************************************************;
* Set library references
*******************************************************************************;
libname raw "../../data/01_raw" access=readonly;
libname sdtm "../../data/04_sdtm";

*******************************************************************************;
* Read raw related records data
*******************************************************************************;
data relrec_raw;
    set raw.relrec;
run;

*******************************************************************************;
* Create RELREC domain
*******************************************************************************;
data sdtm.relrec;
    length STUDYID $12
           RDOMAIN $2
           USUBJID $11
           RELRECID $8
           IDVAR $8
           IDVARVAL $200
           RELTYPE $8
           RELID $200;

    set relrec_raw;

    * Assign STUDYID *;
    STUDYID = "&studyid";

    * Derive USUBJID if not present *;
    if missing(USUBJID) then do;
        if not missing(SITEID) and not missing(SUBJID) then
            USUBJID = catx('-', STUDYID, SITEID, SUBJID);
    end;

    * Ensure RDOMAIN is populated *;
    if missing(RDOMAIN) then RDOMAIN = 'AE';

    * Map IDVAR - variable name that identifies the record *;
    if missing(IDVAR) then do;
        if RDOMAIN = 'AE' then IDVAR = 'AESEQ';
        else if RDOMAIN = 'CM' then IDVAR = 'CMSEQ';
        else if RDOMAIN = 'EX' then IDVAR = 'EXSEQ';
        else if RDOMAIN = 'LB' then IDVAR = 'LBSEQ';
        else if RDOMAIN = 'MH' then IDVAR = 'MHSEQ';
        else if RDOMAIN = 'VS' then IDVAR = 'VSSEQ';
        else if RDOMAIN = 'DS' then IDVAR = 'DSSEQ';
        else if RDOMAIN = 'QS' then IDVAR = 'QSSEQ';
    end;

    * Ensure IDVARVAL is character *;
    if missing(IDVARVAL) and not missing(IDVAR) then
        IDVARVAL = put(input(scan(IDVAR, -1, ' '), best.), best.);

    * Map RELTYPE - type of relationship *;
    if missing(RELTYPE) then RELTYPE = 'ONE';

    * Assign RELID - identifier for related record *;
    if missing(RELID) then do;
        if not missing(USUBJID) and not missing(IDVARVAL) then
            RELID = catx('.', USUBJID, IDVARVAL);
    end;

    * Keep only required variables *;
    keep STUDYID RDOMAIN USUBJID RELRECID IDVAR IDVARVAL RELTYPE RELID;
run;

*******************************************************************************;
* Sort by USUBJID for sequence numbering
*******************************************************************************;
proc sort data=sdtm.relrec;
    by USUBJID RDOMAIN IDVARVAL;
run;

*******************************************************************************;
* Derive RELRECSEQ - sequential numbering per subject
*******************************************************************************;
data sdtm.relrec;
    set sdtm.relrec;
    by USUBJID;

    retain RELRECSEQ;

    if first.USUBJID then RELRECSEQ = 1;
    else RELRECSEQ + 1;
run;

*******************************************************************************;
* Apply variable attributes per SDTM specification
*******************************************************************************;
data sdtm.relrec;
    attrib
        STUDYID    length=$12  label='Study Identifier'
        RDOMAIN    length=$2   label='Related Domain Abbreviation'
        USUBJID    length=$11  label='Unique Subject Identifier'
        RELRECID   length=$8   label='Related Record Identifier'
        RELRECSEQ  length=8    label='Sequence Number'
        IDVAR      length=$8   label='Identifying Variable'
        IDVARVAL   length=$200 label='Identifying Variable Value'
        RELTYPE    length=$8   label='Relationship Type'
        RELID      length=$200 label='Related Identifier';

    set sdtm.relrec;

    * Reorder variables per SDTM standard *;
    keep STUDYID RDOMAIN USUBJID RELRECID RELRECSEQ IDVAR IDVARVAL RELTYPE RELID;
run;

*******************************************************************************;
* Final sort by key variables
*******************************************************************************;
proc sort data=sdtm.relrec;
    by STUDYID USUBJID RELRECSEQ;
run;

*******************************************************************************;
* Create transport file in xport format
*******************************************************************************;
libname xptout xport "../../data/04_sdtm/relrec.xpt";

data xptout.relrec;
    set sdtm.relrec;
run;

libname xptout clear;

*******************************************************************************;
* Generate summary report
*******************************************************************************;
proc freq data=sdtm.relrec;
    tables RDOMAIN RELTYPE / missing;
    title "RELREC Domain Frequency Summary";
run;

proc means data=sdtm.relrec n nmiss min max;
    var RELRECSEQ;
    title "RELREC Sequence Number Statistics";
run;

title;
